// Deduplicate by normalized name
const seen = new Set();
const UNIQUE = INGREDIENTS.filter(i => {
  const k = norm(i.name);
  if (seen.has(k)) return false;
  seen.add(k);
  return true;
});

async function main() {
  const { data: existing, error: fetchErr } = await supabase
    .from('ingredients')
    .select('id, name');
  if (fetchErr) { console.error('Fetch error:', fetchErr.message); process.exit(1); }

  const existingNames = new Set(existing.map(i => norm(i.name)));

  const { data: queue, error: qErr } = await supabase
    .from('ingredient_queue')
    .select('id, name')
    .eq('status', 'pending');
  if (qErr) { console.error('Queue error:', qErr.message); process.exit(1); }

  const toInsert = UNIQUE.filter(i => !existingNames.has(norm(i.name)));
  const toSkip   = UNIQUE.filter(i =>  existingNames.has(norm(i.name)));

  console.log(`${UNIQUE.length} classified ingredients`);
  console.log(`  ${toInsert.length} to insert`);
  console.log(`  ${toSkip.length} already in DB`);

  const queueToMark = queue.filter(q =>
    UNIQUE.some(i => norm(i.name) === norm(q.name))
  );
  const queueUnmatched = queue.filter(q =>
    !UNIQUE.some(i => norm(i.name) === norm(q.name))
  );

  console.log(`\n${queue.length} pending queue items`);
  console.log(`  ${queueToMark.length} matched → will mark done`);
  if (queueUnmatched.length) {
    console.log(`  ${queueUnmatched.length} still unclassified`);
    queueUnmatched.slice(0, 10).forEach(q => console.log(`    - "${q.name}"`));
    if (queueUnmatched.length > 10) console.log(`    ... and ${queueUnmatched.length - 10} more`);
  }

  if (DRY_RUN) {
    console.log('\n[DRY RUN] No changes applied.');
    return;
  }

  let insertOk = 0, insertFail = 0;
  for (const ing of toInsert) {
    const { error } = await supabase.from('ingredients').insert({
      name: ing.name,
      inci_name: ing.inci_name,
      status: ing.status,
      category: ing.category,
      explanation: ing.explanation,
    });
    if (error) {
      console.error(`  ✗ Insert "${ing.name}": ${error.message}`);
      insertFail++;
    } else {
      const flag = ing.status === 'flagged' ? ' ⚑' : '';
      console.log(`  ✓ ${ing.name}${flag}`);
      insertOk++;
    }
  }

  let markOk = 0, markFail = 0;
  for (const q of queueToMark) {
    const { error } = await supabase
      .from('ingredient_queue')
      .update({ status: 'done' })
      .eq('id', q.id);
    if (error) {
      console.error(`  ✗ Mark done "${q.name}": ${error.message}`);
      markFail++;
    } else {
      markOk++;
    }
  }

  console.log(`\nDone.`);
  console.log(`  Inserted: ${insertOk} (${insertFail} failed)`);
  console.log(`  Queue marked done: ${markOk} (${markFail} failed)`);
}

main().catch(console.error);
